input.command:
echo 'import json
from collections import defaultdict
with open("/tmp/all_orders.json") as f:
    orders = json.load(f)
groups = defaultdict(list)
for o in orders:
    key = (o["user_id"], o["total_cents"])
    groups[key].append(o)
for key, group in groups.items():
    if len(group) >= 3:
        group.sort(key=lambda x: x["created_at"])
        for o in group:
            print(json.dumps({"id": o["id"], "user_id": o["user_id"], "total_cents": o["total_cents"], "created_at": o["created_at"], "status": o["status"]}))' > /tmp/find_triple.py

